function relu(value) {
    return Math.max(0, value);
}

function dense(input, weights, biases, useRelu) {
    const output = new Array(biases.length);

    for (
        let outputIndex = 0;
        outputIndex < biases.length;
        outputIndex++
    ) {
        let value = biases[outputIndex];

        for (
            let inputIndex = 0;
            inputIndex < input.length;
            inputIndex++
        ) {
            value +=
                input[inputIndex]
                * weights[inputIndex][outputIndex];
        }

        output[outputIndex] =
            useRelu
                ? relu(value)
                : value;
    }

    return output;
}

function clamp(value, minimum, maximum) {
    return Math.max(
        minimum,
        Math.min(maximum, value)
    );
}

function predictEnhancement(features) {
    const normalized = features.map(
        (value, index) =>
            (
                value
                - MODEL_DATA.inputMean[index]
            )
            / MODEL_DATA.inputScale[index]
    );

    const hidden1 = dense(
        normalized,
        MODEL_DATA.weights[0],
        MODEL_DATA.biases[0],
        true
    );

    const hidden2 = dense(
        hidden1,
        MODEL_DATA.weights[1],
        MODEL_DATA.biases[1],
        true
    );

    const output = dense(
        hidden2,
        MODEL_DATA.weights[2],
        MODEL_DATA.biases[2],
        false
    );

    return {
        brightness: clamp(
            output[0],
            MODEL_DATA.outputBounds.brightness[0],
            MODEL_DATA.outputBounds.brightness[1]
        ),

        contrast: clamp(
            output[1],
            MODEL_DATA.outputBounds.contrast[0],
            MODEL_DATA.outputBounds.contrast[1]
        ),

        saturation: clamp(
            output[2],
            MODEL_DATA.outputBounds.saturation[0],
            MODEL_DATA.outputBounds.saturation[1]
        )
    };
}

function normalizeModelFeatures(features) {
    if (Array.isArray(features)) {
        if (features.length !== 6 || features.some((value) => !Number.isFinite(value))) {
            throw new Error("Некорректный набор признаков изображения.");
        }

        return features;
    }

    if (features && typeof features === "object") {
        const values = [
            features.meanBrightness,
            features.brightnessStd,
            features.meanSaturation,
            features.darkRatio ?? features.darkFraction,
            features.brightRatio ?? features.brightFraction,
            features.brightnessRange ?? features.luminanceRange
        ];

        if (values.every((value) => Number.isFinite(value))) {
            return values;
        }
    }

    throw new Error("Некорректный набор признаков изображения.");
}

self.EnhancementModel = Object.freeze({
    predict(features) {
        return predictEnhancement(normalizeModelFeatures(features));
    }
});
